    const [crop,setCrop]=useState<CropTarget|null>(null),[todayKey,setTodayKey]=useState(taipeiDateKey()),[settingsDirty,setSettingsDirty]=useState(false),[taskBusy,setTaskBusy]=useState(""),[taskConfirm,setTaskConfirm]=useState<DailyTaskRecord|null>(null);
    const revisionRef=useRef(0),settingsDirtyRef=useRef(false),toastTimerRef=useRef<ReturnType<typeof setTimeout>|null>(null);
    const child = data.children.find(c => c.id === cid) || data.children[0];
    useEffect(() => { reloadState().finally(() => setLoading(false)); }, []);
    useEffect(()=>{const warn=(event:BeforeUnloadEvent)=>{if(!settingsDirty)return;event.preventDefault();event.returnValue=""};window.addEventListener("beforeunload",warn);return()=>window.removeEventListener("beforeunload",warn)},[settingsDirty]);
    useEffect(()=>{settingsDirtyRef.current=settingsDirty},[settingsDirty]);
    useEffect(()=>{const refreshDay=()=>setTodayKey(current=>{const next=taipeiDateKey();if(next!==current&&!settingsDirtyRef.current)void reloadState();return next});const timer=setInterval(refreshDay,60000);window.addEventListener("focus",refreshDay);return()=>{clearInterval(timer);window.removeEventListener("focus",refreshDay)}},[]);
    const say = (s: string) => { if(toastTimerRef.current)clearTimeout(toastTimerRef.current);setToast(s);toastTimerRef.current=setTimeout(() => setToast(""), 2800); };
    function normalizedClientState(loaded:Partial<State>):State{return {...fallback,...loaded,children:Array.isArray(loaded.children)?loaded.children:fallback.children,entries:Array.isArray(loaded.entries)?loaded.entries:[],rewards:Array.isArray(loaded.rewards)?loaded.rewards:[],templates:Array.isArray(loaded.templates)?loaded.templates:[],redemptions:Array.isArray(loaded.redemptions)?loaded.redemptions:[],specialRewards:Array.isArray(loaded.specialRewards)?loaded.specialRewards:[],rewardIconLibrary:Array.isArray(loaded.rewardIconLibrary)?loaded.rewardIconLibrary:[],dailyTasks:Array.isArray(loaded.dailyTasks)?loaded.dailyTasks:[],dailyTaskRecords:Array.isArray(loaded.dailyTaskRecords)?loaded.dailyTaskRecords:[],dailyTaskSettings:loaded.dailyTaskSettings&&typeof loaded.dailyTaskSettings==="object"?loaded.dailyTaskSettings:{}}}
