    async function reloadState(){try{const response=await fetch(`/api/state?t=${Date.now()}`,{cache:"no-store"}),result=await response.json();if(!response.ok||!result.state)throw new Error(result.error||"無法讀取資料");const applied=applyServerPayload(result);setTodayKey(taipeiDateKey());return applied}catch{return false}}
