    async function persist(next: State, newPassword?: string) { setData(next);try{const r = await fetch("/api/state", { method: "POST", headers: { "content-type": "application/json" }, body: JSON.stringify({ action: "save", state: next, password, newPassword,expectedRevision:revisionRef.current }) }),x=await r.json();if(!r.ok){await reloadState();say(x.error || "儲存失敗");return false}applyServerPayload(x);setSettingsDirty(false);if(newPassword){setPassword(newPassword);setNewPasswordDraft("")}say("已儲存所有設定");return true}catch{await reloadState();say("儲存失敗，請檢查網路後再試");return false}}
    async function submitPending(action:"child_entry"|"child_redemption",record:Entry|Redeem,next:State){setData(next);try{const r=await fetch("/api/state",{method:"POST",headers:{"content-type":"application/json"},body:JSON.stringify({action,record})}),x=await r.json();if(!r.ok){await reloadState();say(x.error||"送出失敗");return false}applyServerPayload(x);say("已送出，等待家長確認");return true}catch{await reloadState();say("送出失敗，請檢查網路後再試");return false}}
